import{_ as a,o as t,c as l,a0 as n}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"Enter Results Manually","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/manual-input.md","filePath":"how-to/manual-input.md"}'),o={name:"how-to/manual-input.md"};function s(r,e,i,h,c,u){return t(),l("div",null,[...e[0]||(e[0]=[n('<h1 id="enter-results-manually" tabindex="-1">Enter Results Manually <a class="header-anchor" href="#enter-results-manually" aria-label="Permalink to &quot;Enter Results Manually&quot;">​</a></h1><p>Manual Input is the fastest way to type one event/date batch directly without using screenshot OCR.</p><blockquote><p>Screenshot placeholder: manual-input.png</p></blockquote><h2 id="what-this-page-does" tabindex="-1">What this page does <a class="header-anchor" href="#what-this-page-does" aria-label="Permalink to &quot;What this page does&quot;">​</a></h2><p>The page loads all players for one alliance, then lets you enter:</p><ul><li>score</li><li>position</li><li>participation status</li></ul><p>for one event and one date at a time.</p><h2 id="basic-workflow" tabindex="-1">Basic workflow <a class="header-anchor" href="#basic-workflow" aria-label="Permalink to &quot;Basic workflow&quot;">​</a></h2><ol><li>Choose the kingdom and alliance.</li><li>Choose the event and date.</li><li>If needed, choose an existing instance or let the app create or reuse one by date.</li><li>If the event uses stages, choose <strong>Stage Data</strong> or <strong>Total Data</strong>.</li><li>Fill in the player rows.</li><li>Save the batch.</li></ol><p>After saving, the app opens the related record batch.</p><h2 id="special-event-behavior" tabindex="-1">Special event behavior <a class="header-anchor" href="#special-event-behavior" aria-label="Permalink to &quot;Special event behavior&quot;">​</a></h2><ul><li>staged events show <strong>Stage Data</strong> and <strong>Total Data</strong></li><li>cumulative events save dated running totals rather than stacking repeated totals</li></ul><p>If the event uses stages and you stay in <strong>Stage Data</strong>, you must choose the stage/day.</p><h2 id="useful-shortcuts-on-the-page" tabindex="-1">Useful shortcuts on the page <a class="header-anchor" href="#useful-shortcuts-on-the-page" aria-label="Permalink to &quot;Useful shortcuts on the page&quot;">​</a></h2><p>The page links directly to:</p><ul><li><strong>Manual players</strong></li><li><strong>Record batches</strong></li><li><strong>Reload context</strong></li><li><strong>Event fields</strong></li></ul><h2 id="lock-warning" tabindex="-1">Lock warning <a class="header-anchor" href="#lock-warning" aria-label="Permalink to &quot;Lock warning&quot;">​</a></h2><p>If the related instance is locked, normal editing rules apply. Use <a href="./session-lock.html">Locked Instances &amp; Unlock Requests</a> if late changes are needed.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./manual-players.html">Add Players During Manual Entry</a></li><li><a href="./records.html">Records &amp; Record Batches</a></li><li><a href="./create-instance.html">Create an Event Instance</a></li></ul>',20)])])}const g=a(o,[["render",s]]);export{p as __pageData,g as default};
